/* ── Dark: iOS / Apple HIG style ── */
.dark {
  /* Core surfaces — true black base, layered gray system */
  --background:         #000000;
  --foreground:         #ffffff;

  /* Cards / sheets — iOS secondary grouped background */
  --card:               #1c1c1e;
  --card-foreground:    #ffffff;

  /* Popovers / menus — slightly elevated */
  --popover:            #2c2c2e;
  --popover-foreground: #ffffff;

  /* Primary action — iOS system blue */
  --primary:            #0a84ff;
  --primary-foreground: #ffffff;

  /* Secondary surfaces */
  --secondary:          #2c2c2e;
  --secondary-foreground: #ebebf5;

  /* Muted — iOS tertiary label */
  --muted:              #2c2c2e;
  --muted-foreground:   #8e8e93;

  /* Accent — iOS fill / interactive highlight */
  --accent:             #38383a;
  --accent-foreground:  #ffffff;

  /* Destructive — iOS system red */
  --destructive:        #ff453a;
  --destructive-foreground: #ffffff;

  /* Borders & dividers — iOS separator (white 15%) */
  --border:             rgba(255, 255, 255, 0.12);
  --input:              rgba(255, 255, 255, 0.10);
  --ring:               #0a84ff;

  /* Chart palette — iOS system colors */
  --chart-1:            #0a84ff;   /* blue   */
  --chart-2:            #30d158;   /* green  */
  --chart-3:            #bf5af2;   /* purple */
  --chart-4:            #ff9f0a;   /* orange */
  --chart-5:            #ff453a;   /* red    */

  /* Sidebar — slightly elevated from pure black */
  --sidebar:            #0d0d0f;
  --sidebar-foreground: #ebebf5;
  --sidebar-primary:    #0a84ff;
  --sidebar-primary-foreground: #ffffff;
  --sidebar-accent:     #2c2c2e;
  --sidebar-accent-foreground:  #ffffff;
  --sidebar-border:     rgba(255, 255, 255, 0.08);
  --sidebar-ring:       #0a84ff;

  /* Apple semantic tints — used by component classes */
  --apple-blue:         #0a84ff;
  --apple-green:        #30d158;
  --apple-orange:       #ff9f0a;
  --apple-red:          #ff453a;
  --apple-purple:       #bf5af2;
  --apple-teal:         #5ac8fa;
  --apple-indigo:       #5e5ce6;
}

