args.new_str:
@layer utilities {
  /* iOS-style card surface — deep gray, soft shadow */
  .analytics-panel {
    @apply rounded-2xl border border-border bg-card text-card-foreground;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.45), 0 1px 3px rgba(0, 0, 0, 0.3);
  }

  /* Legacy glass aliases — now maps to iOS card */
  .glass-card {
    @apply rounded-2xl border border-border bg-card text-card-foreground;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.45), 0 1px 3px rgba(0, 0, 0, 0.3);
  }

  /* Header glass effect — dark, blurred */
  .glass {
    @apply border-b border-border bg-background/80 backdrop-blur-xl;
  }

  /* Soft drop shadow presets */
  .apple-shadow-sm {
    box-shadow: 0 1px 6px rgba(0, 0, 0, 0.35), 0 1px 2px rgba(0, 0, 0, 0.25);
  }
  .apple-shadow {
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5), 0 2px 6px rgba(0, 0, 0, 0.35);
  }

  /* Metric number display */
  .metric-display {
    font-size: clamp(1.75rem, 3vw, 2.25rem);
    font-weight: 700;
    letter-spacing: -0.03em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
  }

  .metric-display-sm {
    font-size: clamp(1.375rem, 2.5vw, 1.75rem);
    font-weight: 700;
    letter-spacing: -0.025em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
  }

  /* iOS thin separator line */
  .ios-separator {
    height: 0.5px;
    background: var(--border);
    margin-left: 1.25rem;
  }

  /* iOS pill badge */
  .ios-pill {
    @apply inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold;
  }

  /* iOS blue accent glow — for interactive elements */
  .ios-glow {
    box-shadow: 0 0 0 3px rgba(10, 132, 255, 0.25);
  }

  @media (prefers-reduced-motion: reduce) {
    .animate-slide-up,
    .animate-pulse-glow {
      animation: none;
    }
  }
}

