import { cn } from '@/lib/utils'

interface GlassCardProps {
  eyebrow?: string
  title?: string
  subtitle?: string
  action?: React.ReactNode
  children?: React.ReactNode
  className?: string
  contentClassName?: string
  noPadding?: boolean
}

export function GlassCard({
  eyebrow,
  title,
  subtitle,
  action,
  children,
  className,
  contentClassName,
  noPadding,
}: GlassCardProps) {
  const hasHeader = eyebrow || title || subtitle || action

  return (
    <section
      className={cn(
        // iOS card: deep gray surface (#1c1c1e), rounded-2xl, soft dark shadow
        'overflow-hidden rounded-2xl border border-white/[0.08] bg-[#1c1c1e] text-foreground',
        'shadow-[0_2px_16px_rgba(0,0,0,0.5),0_1px_4px_rgba(0,0,0,0.35)]',
        className,
      )}
    >
      {hasHeader && (
        <div className="flex items-start justify-between gap-4 border-b border-white/[0.07] px-5 py-4">
          <div className="min-w-0">
            {eyebrow && (
              <p className="text-[11px] font-semibold uppercase tracking-wider text-white/40">{eyebrow}</p>
            )}
            {title && (
              <h2 className={cn('font-semibold tracking-tight text-white', eyebrow ? 'mt-0.5 text-sm' : 'text-sm')}>
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="mt-0.5 text-xs text-white/40">{subtitle}</p>
            )}
          </div>
          {action}
        </div>
      )}
      <div className={cn(!noPadding && 'p-5', hasHeader && children && !noPadding && 'pt-4', contentClassName)}>
        {children}
      </div>
    </section>
  )
}

