import { Cell, Pie, PieChart, ResponsiveContainer } from 'recharts'
import { ChartContainer, ChartTooltip, ChartTooltipContent, type ChartConfig } from '@/components/ui/chart'
import { GlassCard } from '@/components/ios-glass-card'
import { chartColorForKey, chartColor } from '@/lib/chart-colors'
import type { DashboardSourceItem } from '@/api/dashboard.types'

interface Props {
  sources: DashboardSourceItem[]
}

const SOURCE_LABEL: Record<string, string> = {
  internal: 'Internal',
  local_people: 'Warga Lokal',
  monitoring: 'Monitoring',
}

const chartConfig = {
  count: { label: 'Tiket', color: 'var(--chart-1)' },
} satisfies ChartConfig

export function DashboardSourceChart({ sources }: Props) {
  const data = sources
    .filter((s) => s.count > 0)
    .map((s, i) => ({
      key: s.source,
      name: SOURCE_LABEL[s.source] ?? s.source,
      value: s.count,
      color: chartColorForKey(s.source) ?? chartColor(i),
    }))

  const total = data.reduce((sum, d) => sum + d.value, 0)

  if (data.length === 0) {
    return (
      <GlassCard eyebrow="Distribusi" title="Sumber Laporan">
        <p className="text-sm text-muted-foreground">Tidak ada data</p>
      </GlassCard>
    )
  }

  return (
    <GlassCard eyebrow="Distribusi" title="Sumber Laporan" noPadding contentClassName="px-6 pb-6 pt-4">
      <div className="flex flex-col items-center gap-6 sm:flex-row sm:items-center">
        <div className="relative shrink-0">
          <ChartContainer config={chartConfig} className="size-[160px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <ChartTooltip content={<ChartTooltipContent hideLabel nameKey="name" />} />
                <Pie
                  data={data}
                  cx="50%"
                  cy="50%"
                  innerRadius={46}
                  outerRadius={70}
                  paddingAngle={3}
                  dataKey="value"
                  nameKey="name"
                  strokeWidth={2}
                  stroke="var(--background)"
                >
                  {data.map((entry) => (
                    <Cell key={entry.key} fill={entry.color} />
                  ))}
                </Pie>
              </PieChart>
            </ResponsiveContainer>
          </ChartContainer>
          <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center">
            <span className="metric-display-sm text-foreground">{total}</span>
            <span className="text-xs text-muted-foreground">total</span>
          </div>
        </div>

        <div className="flex w-full flex-1 flex-col gap-3 pt-2">
          {data.map((item) => {
            const pct = total > 0 ? Math.round((item.value / total) * 100) : 0
            return (
              <div key={item.key} className="flex flex-col gap-1.5">
                <div className="flex items-center justify-between gap-3">
                  <div className="flex items-center gap-2">
                    <span className="size-2.5 rounded-full" style={{ background: item.color }} />
                    <span className="text-sm text-muted-foreground">{item.name}</span>
                  </div>
                  <span className="text-sm font-semibold tabular-nums text-foreground">{item.value}</span>
                </div>
                <div className="h-1 overflow-hidden rounded-full bg-secondary/80">
                  <div
                    className="h-full rounded-full transition-all duration-700"
                    style={{ width: `${pct}%`, background: item.color }}
                  />
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </GlassCard>
  )
}

=== Operation 2 Result (Text) ===
import * as React from 'react'
import { Cell, Pie, PieChart, ResponsiveContainer, Tooltip } from 'recharts'
import { GlassCard } from '@/components/ios-glass-card'
import { chartColor, chartToken } from '@/lib/chart-colors'
import type { DashboardPriorityItem } from '@/api/dashboard.types'

interface Props {
  priorities: DashboardPriorityItem[]
}

const PRIORITY_LABEL: Record<string, string> = {
  critical: 'Kritis',
  high: 'Tinggi',
  medium: 'Sedang',
  low: 'Rendah',
}

const PRIORITY_COLOR: Record<string, string> = {
  critical: chartToken(5),
  high: chartToken(4),
  medium: chartToken(1),
  low: chartToken(2),
}

const ORDER = ['critical', 'high', 'medium', 'low']

// Custom tooltip
function CustomTooltip({
  active,
  payload,
  total,
}: {
  active?: boolean
  payload?: Array<{ name: string; value: number; payload: { color: string } }>
  total: number
}) {
  if (!active || !payload?.length) return null
  const item = payload[0]
  const pct = total > 0 ? Math.round((item.value / total) * 100) : 0
  return (
    <div className="rounded-lg border border-border/50 bg-background px-3 py-2 text-xs shadow-xl">
      <p className="font-medium text-foreground">{item.name}</p>
      <p className="mt-0.5 text-muted-foreground">
        <span className="font-mono font-semibold text-foreground">{item.value}</span>
        {' '}tiket · {pct}%
      </p>
    </div>
  )
}

// Center label rendered via foreignObject
function CenterLabel({ cx, cy, total }: { cx: number; cy: number; total: number }) {
  return (
    <text x={cx} y={cy} textAnchor="middle" dominantBaseline="middle">
      <tspan
        x={cx}
        dy="-0.4em"
        fontSize="22"
        fontWeight="700"
        fill="currentColor"
        className="fill-foreground"
      >
        {total}
      </tspan>
      <tspan
        x={cx}
        dy="1.4em"
        fontSize="11"
        fill="currentColor"
        className="fill-muted-foreground"
      >
        Total
      </tspan>
    </text>
  )
}

export function DashboardPriorityChart({ priorities }: Props) {
  const [activeIndex, setActiveIndex] = React.useState<number | null>(null)

  const data = [...priorities]
    .filter((p) => p.count > 0)
    .sort((a, b) => ORDER.indexOf(a.priority) - ORDER.indexOf(b.priority))
    .map((p, i) => ({
      key: p.priority,
      name: PRIORITY_LABEL[p.priority] ?? p.priority,
      value: p.count,
      color: PRIORITY_COLOR[p.priority] ?? chartColor(i),
    }))

  const total = data.reduce((sum, d) => sum + d.value, 0)

  if (data.length === 0) {
    return (
      <GlassCard eyebrow="Distribusi" title="Prioritas Tiket">
        <p className="text-sm text-muted-foreground">Tidak ada data</p>
      </GlassCard>
    )
  }

  return (
    <GlassCard eyebrow="Distribusi" title="Prioritas Tiket" noPadding contentClassName="px-6 pb-6 pt-4">
      {/* Donut chart */}
      <div className="mx-auto h-[220px] w-full max-w-[240px]">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Tooltip
              content={<CustomTooltip total={total} />}
              cursor={false}
            />
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={62}
              outerRadius={90}
              paddingAngle={2}
              dataKey="value"
              nameKey="name"
              strokeWidth={0}
              animationBegin={0}
              animationDuration={600}
              onMouseEnter={(_, index) => setActiveIndex(index)}
              onMouseLeave={() => setActiveIndex(null)}
            >
              {data.map((entry, index) => (
                <Cell
                  key={entry.key}
                  fill={entry.color}
                  opacity={activeIndex === null || activeIndex === index ? 1 : 0.45}
                  style={{ transition: 'opacity 150ms ease', cursor: 'pointer' }}
                />
              ))}
            </Pie>
            {/* Center total */}
            <text x="50%" y="50%" textAnchor="middle" dominantBaseline="middle">
              <tspan
                x="50%"
                dy="-0.4em"
                fontSize="22"
                fontWeight="700"
                className="fill-foreground"
              >
                {total}
              </tspan>
              <tspan
                x="50%"
                dy="1.4em"
                fontSize="11"
                className="fill-muted-foreground"
              >
                Total
              </tspan>
            </text>
          </PieChart>
        </ResponsiveContainer>
      </div>

      {/* Legend */}
      <div className="mt-4 grid grid-cols-2 gap-2">
        {data.map((item, index) => {
          const pct = total > 0 ? Math.round((item.value / total) * 100) : 0
          const isActive = activeIndex === index
          return (
            <div
              key={item.key}
              className="flex cursor-pointer items-center gap-2.5 rounded-lg border border-border bg-muted/30 px-3 py-2.5 transition-colors hover:bg-muted/60"
              onMouseEnter={() => setActiveIndex(index)}
              onMouseLeave={() => setActiveIndex(null)}
              style={{ opacity: activeIndex === null || isActive ? 1 : 0.55, transition: 'opacity 150ms ease' }}
            >
              {/* Color dot */}
              <span
                className="size-2.5 shrink-0 rounded-full"
                style={{ background: item.color }}
              />
              <div className="min-w-0 flex-1">
                <p className="truncate text-xs font-medium text-foreground">{item.name}</p>
                <p className="text-xs text-muted-foreground">
                  <span className="font-mono font-semibold text-foreground">{item.value}</span>
                  {' ·'} {pct}%
                </p>
              </div>
            </div>
          )
        })}
      </div>
    </GlassCard>
  )
}

