const COLOR_MAP: Record<string, string> = {
  blue:   '#0a84ff',
  green:  '#30d158',
  orange: '#ff9f0a',
  red:    '#ff453a',
  purple: '#bf5af2',
  teal:   '#5ac8fa',
  indigo: '#5e5ce6',
  yellow: '#ffd60a',
  pink:   '#ff375f',
}

interface Props {
  title: string
  value: string | number
  icon: React.ReactNode
  sub?: string
  /** Hex color string or iOS color name (e.g. "blue", "green", "red") */
  accent?: string
  /** @deprecated use accent */
  color?: string
}

export function DashboardMetricCard({ title, value, sub, icon, accent, color }: Props) {
  const resolveColor = (c?: string) => {
    if (!c) return '#0a84ff'
    return COLOR_MAP[c] ?? c
  }

  const accentColor = resolveColor(accent ?? color)

  return (
    <div
      className="flex flex-col gap-4 overflow-hidden rounded-2xl border border-white/[0.08] bg-[#1c1c1e] p-5"
      style={{ boxShadow: '0 2px 16px rgba(0,0,0,0.5), 0 1px 4px rgba(0,0,0,0.35)' }}
    >
      {/* Icon + label row */}
      <div className="flex items-center justify-between gap-2">
        <p className="text-[11px] font-semibold uppercase tracking-wider text-white/40">{title}</p>
        <span
          className="flex size-7 items-center justify-center rounded-xl [&_svg]:size-3.5"
          style={{ background: `${accentColor}22`, color: accentColor }}
        >
          {icon}
        </span>
      </div>

      {/* Value */}
      <div>
        <div className="metric-display text-white">{value}</div>
        {sub && (
          <p className="mt-1.5 text-xs text-white/40">{sub}</p>
        )}
      </div>

      {/* Bottom accent line */}
      <div className="h-0.5 w-8 rounded-full opacity-60" style={{ background: accentColor }} />
    </div>
  )
}

