      0 2px 8px rgba(0, 0, 0, 0.3),
      inset 0 1px 0 rgba(255, 255, 255, 0.12);
    color: #ffffff;
  }

  /* Legacy alias */
  .glass-card {
    background: rgba(255, 255, 255, 0.07);
    backdrop-filter: blur(24px) saturate(180%);
    -webkit-backdrop-filter: blur(24px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.13);
    border-radius: 20px;
    box-shadow:
      0 8px 32px rgba(0, 0, 0, 0.45),
      0 2px 8px rgba(0, 0, 0, 0.3),
      inset 0 1px 0 rgba(255, 255, 255, 0.12);
    color: #ffffff;
  }

  /* Header/nav glass bar */
  .glass {
    background: rgba(10, 10, 14, 0.72);
    backdrop-filter: blur(32px) saturate(200%);
    -webkit-backdrop-filter: blur(32px) saturate(200%);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  }

  /* Elevated glass — popovers, menus */
  .glass-elevated {
    background: rgba(40, 40, 48, 0.88);
    backdrop-filter: blur(40px) saturate(200%);
    -webkit-backdrop-filter: blur(40px) saturate(200%);
    border: 1px solid rgba(255, 255, 255, 0.14);
    box-shadow:
      0 20px 60px rgba(0, 0, 0, 0.6),
      inset 0 1px 0 rgba(255, 255, 255, 0.15);
  }

  /* Shadows */
  .apple-shadow-sm {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.35), inset 0 1px 0 rgba(255,255,255,0.08);
  }
  .apple-shadow {
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.55), inset 0 1px 0 rgba(255,255,255,0.10);
  }

  /* Metric number — heavy weight, crisp */
  .metric-display {
    font-size: clamp(1.75rem, 3vw, 2.25rem);
    font-weight: 700;
    letter-spacing: -0.03em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
    text-shadow: 0 1px 8px rgba(0, 0, 0, 0.4);
  }

  .metric-display-sm {
    font-size: clamp(1.375rem, 2.5vw, 1.75rem);
    font-weight: 700;
    letter-spacing: -0.025em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
    text-shadow: 0 1px 6px rgba(0, 0, 0, 0.35);
  }

  /* iOS hairline separator */
  .ios-separator {
    height: 0.5px;
    background: rgba(255, 255, 255, 0.10);
    margin-left: 1.25rem;
  }

  /* iOS pill badge */
  .ios-pill {
    @apply inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold;
  }

  /* Blue focus ring glow */
  .ios-glow {
    box-shadow: 0 0 0 3px rgba(10, 132, 255, 0.30), 0 0 16px rgba(10, 132, 255, 0.15);
  }

  /* Frosted glass input */
  .glass-input {
    background: rgba(255, 255, 255, 0.08);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 10px;
    color: #fff;
  }
  .glass-input:focus {
    outline: none;
    border-color: rgba(10, 132, 255, 0.6);
    box-shadow: 0 0 0 3px rgba(10, 132, 255, 0.20);
  }

  @media (prefers-reduced-motion: reduce) {
    .animate-slide-up,
    .animate-pulse-glow {
      animation: none;
    }
  }
}

