import { cn } from '@/lib/utils'

interface GlassCardProps {
  eyebrow?: string
  title?: string
  subtitle?: string
  action?: React.ReactNode
  children?: React.ReactNode
  className?: string
  contentClassName?: string
  noPadding?: boolean
}

export function GlassCard({
  eyebrow,
  title,
  subtitle,
  action,
  children,
  className,
  contentClassName,
  noPadding,
}: GlassCardProps) {
  const hasHeader = eyebrow || title || subtitle || action

  return (
    <section
      className={cn('overflow-hidden rounded-[20px]', className)}
      style={{
        background: 'rgba(255, 255, 255, 0.07)',
        backdropFilter: 'blur(24px) saturate(180%)',
        WebkitBackdropFilter: 'blur(24px) saturate(180%)',
        border: '1px solid rgba(255, 255, 255, 0.13)',
        boxShadow: [
          '0 8px 32px rgba(0, 0, 0, 0.45)',
          '0 2px 8px rgba(0, 0, 0, 0.3)',
          'inset 0 1px 0 rgba(255, 255, 255, 0.14)',
          'inset 0 -1px 0 rgba(0, 0, 0, 0.12)',
        ].join(', '),
      }}
    >
      {hasHeader && (
        <div
          className="flex items-start justify-between gap-4 px-5 py-4"
          style={{ borderBottom: '1px solid rgba(255, 255, 255, 0.08)' }}
        >
          <div className="min-w-0">
            {eyebrow && (
              <p className="text-[10px] font-semibold uppercase tracking-widest text-white/40">
                {eyebrow}
              </p>
            )}
            {title && (
              <h2 className={cn(
                'font-semibold tracking-tight text-white',
                eyebrow ? 'mt-0.5 text-sm' : 'text-sm',
              )}>
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="mt-0.5 text-xs text-white/40">{subtitle}</p>
            )}
          </div>
          {action}
        </div>
      )}
      <div className={cn(!noPadding && 'p-5', hasHeader && children && !noPadding && 'pt-4', contentClassName)}>
