const COLOR_MAP: Record<string, string> = {
  blue:   '#0a84ff',
  green:  '#30d158',
  orange: '#ff9f0a',
  red:    '#ff453a',
  purple: '#bf5af2',
  teal:   '#5ac8fa',
  indigo: '#5e5ce6',
  yellow: '#ffd60a',
  pink:   '#ff375f',
}

interface Props {
  title: string
  value: string | number
  icon: React.ReactNode
  sub?: string
  /** Hex color or named iOS color: "blue" | "green" | "red" | "orange" | "purple" */
  accent?: string
  /** @deprecated use accent */
  color?: string
}

export function DashboardMetricCard({ title, value, sub, icon, accent, color }: Props) {
  const resolveColor = (c?: string) => {
    if (!c) return '#0a84ff'
    return COLOR_MAP[c] ?? c
  }

  const accentColor = resolveColor(accent ?? color)

  return (
    <div
      className="relative flex flex-col gap-4 overflow-hidden rounded-[20px] p-5"
      style={{
        background: 'rgba(255, 255, 255, 0.07)',
        backdropFilter: 'blur(24px) saturate(180%)',
        WebkitBackdropFilter: 'blur(24px) saturate(180%)',
        border: '1px solid rgba(255, 255, 255, 0.13)',
        boxShadow: [
          '0 8px 32px rgba(0, 0, 0, 0.4)',
          '0 2px 8px rgba(0, 0, 0, 0.25)',
          'inset 0 1px 0 rgba(255, 255, 255, 0.14)',
        ].join(', '),
      }}
    >
      {/* Subtle tinted glow from accent in top corner */}
      <div
        aria-hidden
        className="pointer-events-none absolute -right-8 -top-8 size-28 rounded-full opacity-20"
        style={{
          background: `radial-gradient(circle, ${accentColor} 0%, transparent 70%)`,
          filter: 'blur(20px)',
        }}
      />

      {/* Icon + label */}
      <div className="relative flex items-center justify-between gap-2">
        <p className="text-[10px] font-semibold uppercase tracking-widest text-white/45">{title}</p>
        <span
          className="flex size-8 shrink-0 items-center justify-center rounded-xl [&_svg]:size-4"
          style={{
            background: `${accentColor}22`,
            color: accentColor,
            boxShadow: `0 0 0 1px ${accentColor}30`,
          }}
        >
          {icon}
        </span>
      </div>

      {/* Value */}
      <div className="relative">
        <div className="metric-display text-white">{value}</div>
        {sub && (
          <p className="mt-1.5 text-xs text-white/40">{sub}</p>
        )}
      </div>

      {/* Bottom accent bar */}
      <div
        className="h-[2px] w-10 rounded-full"
        style={{
          background: `linear-gradient(90deg, ${accentColor}, transparent)`,
          opacity: 0.7,
        }}
      />
    </div>
  )
}

