    -moz-osx-font-smoothing: grayscale;
  }
  body {
    @apply bg-background text-foreground;
    font-family: -apple-system, BlinkMacSystemFont, "SF Pro Display", "SF Pro Text",
      "Inter Variable", "Helvetica Neue", Arial, sans-serif;
    letter-spacing: -0.011em;
  }

  /* Scrollbar — iOS-style minimal */
  ::-webkit-scrollbar {
    width: 4px;
    height: 4px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.15);
    border-radius: 2px;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 255, 255, 0.25);
  }
}

@layer utilities {
  /* ── Card: light = shadcn standard, dark = frosted glass ── */
  .analytics-panel {
    @apply rounded-[20px] border border-border bg-card text-card-foreground;
    box-shadow: 0 1px 4px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.04);
  }
  .dark .analytics-panel {
    background: rgba(28, 28, 32, 0.82);
    backdrop-filter: blur(20px) saturate(160%);
    -webkit-backdrop-filter: blur(20px) saturate(160%);
    border: 1px solid rgba(255, 255, 255, 0.10);
    box-shadow:
      0 8px 32px rgba(0, 0, 0, 0.40),
      0 2px 6px rgba(0, 0, 0, 0.25),
      inset 0 1px 0 rgba(255, 255, 255, 0.09);
  }

  /* Legacy alias */
  .glass-card {
    @apply rounded-[20px] border border-border bg-card text-card-foreground;
    box-shadow: 0 1px 4px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.04);
  }
  .dark .glass-card {
    background: rgba(28, 28, 32, 0.82);
    backdrop-filter: blur(20px) saturate(160%);
    -webkit-backdrop-filter: blur(20px) saturate(160%);
    border: 1px solid rgba(255, 255, 255, 0.10);
    box-shadow:
      0 8px 32px rgba(0, 0, 0, 0.40),
      0 2px 6px rgba(0, 0, 0, 0.25),
      inset 0 1px 0 rgba(255, 255, 255, 0.09);
  }

  /* Header bar */
  .glass {
    @apply border-b border-border bg-background/90 backdrop-blur-xl;
  }
  .dark .glass {
    background: rgba(8, 8, 12, 0.80);
    backdrop-filter: blur(28px) saturate(180%);
    -webkit-backdrop-filter: blur(28px) saturate(180%);
    border-bottom: 1px solid rgba(255, 255, 255, 0.07);
  }

  /* Shadows */
  .apple-shadow-sm {
    box-shadow: 0 1px 4px rgba(0,0,0,0.08), 0 2px 8px rgba(0,0,0,0.05);
  }
  .dark .apple-shadow-sm {
    box-shadow: 0 4px 16px rgba(0,0,0,0.30), inset 0 1px 0 rgba(255,255,255,0.07);
  }
  .apple-shadow {
    box-shadow: 0 2px 8px rgba(0,0,0,0.08), 0 8px 24px rgba(0,0,0,0.06);
  }
  .dark .apple-shadow {
    box-shadow: 0 12px 40px rgba(0,0,0,0.50), inset 0 1px 0 rgba(255,255,255,0.08);
  }

  /* Metric number */
  .metric-display {
    font-size: clamp(1.75rem, 3vw, 2.25rem);
    font-weight: 700;
    letter-spacing: -0.03em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
  }
  .metric-display-sm {
    font-size: clamp(1.375rem, 2.5vw, 1.75rem);
    font-weight: 700;
    letter-spacing: -0.025em;
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
  }

  /* Separator */
  .ios-separator {
    height: 0.5px;
    @apply bg-border;
    margin-left: 1.25rem;
  }

  /* iOS pill badge */
  .ios-pill {
    @apply inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold;
  }

  /* Focus glow */
  .ios-glow {
    box-shadow: 0 0 0 3px rgba(10, 132, 255, 0.28);
  }

  @media (prefers-reduced-motion: reduce) {
    .animate-slide-up,
    .animate-pulse-glow { animation: none; }
  }
}

