              >
                {i + 1}
              </span>
              <div className="min-w-0 flex-1">
                <p className="truncate text-sm font-medium text-foreground">{loc.siteName}</p>
                <p className="truncate text-xs text-muted-foreground">{loc.locationName}</p>
              </div>
              <span
                className="shrink-0 rounded-lg px-2 py-0.5 text-xs font-semibold tabular-nums text-foreground"
                style={{ background: 'rgba(10,132,255,0.15)', color: '#0a84ff' }}
              >
                {loc.ticketCount}
              </span>
            </div>
          </GroupedListRow>
        ))}
      </GroupedListBody>
    </GlassCard>
  )
}

